#!/usr/bin/env dotnet
#:property InvariantGlobalization=false

// Find the earliest Friday the 13th in the proleptic Gregorian calendar (starting 0001-01-01)
// and count total Friday the 13ths in a full 400-year cycle.

// Find the earliest Friday the 13th
var date = new DateOnly(1, 1, 13); // start checking from the 13th of each month
DateOnly? earliest = null;

for (int year = 1; year <= 400 && earliest is null; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var candidate = new DateOnly(year, month, 13);
        if (candidate.DayOfWeek == DayOfWeek.Friday)
        {
            earliest = candidate;
            break;
        }
    }
}

Console.WriteLine($"Earliest Friday the 13th: {earliest:yyyy-MM-dd} ({earliest!.Value.DayOfWeek})");

// Count Friday the 13ths in a full 400-year cycle (years 1–400)
int count = 0;
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        if (new DateOnly(year, month, 13).DayOfWeek == DayOfWeek.Friday)
            count++;
    }
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");

